SELECT property_location 
FROM properties 
ORDER BY property_location;

SELECT SUM(total_units) AS total_units
FROM properties
WHERE property_manager = 'John Doe';

SELECT property_id, property_full_address
FROM properties
ORDER BY property_id ASC;

SELECT property_full_address
FROM properties
ORDER BY property_full_address;

SELECT DISTINCT property_manager
FROM properties
WHERE last_inspection_date = (
    SELECT MAX(last_inspection_date) FROM properties
);

SELECT property_full_address
FROM properties
ORDER BY property_id;

SELECT property_full_address
FROM properties
ORDER BY property_full_address ASC;
